+/**
+ * Notification log model — records every notification sent through the system.
+ *
+ * Captures recipient, channel, type, timestamp, and delivery status for
+ * auditing, debugging, and history queries.
+ */
+
+import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';
+
+export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';
+
+export interface NotificationLogEntry {
+  id: string;
+  notificationId: string;
+  recipient: string;
+  channel: NotificationChannel;
+  type: NotificationType;
+  priority: NotificationPriority;
+  subject: string;
+  status: DeliveryStatus;
+  error?: string;
+  metadata?: Record<string, string>;
+  timestamp: Date;
+}
+
+export interface NotificationHistoryQuery {
+  recipient?: string;
+  type?: NotificationType;
+  channel?: NotificationChannel;
+  status?: DeliveryStatus;
+  from?: Date;
+  to?: Date;
+}

