+/**
+ * Repository for notification log entries.
+ *
+ * Extends BaseRepository with query methods for filtering by
+ * recipient, type, channel, status, and date range.
+ */
+
+import type { DatabaseRecord } from '../utils/database.js';
+import type { Database } from '../utils/database.js';
+import type { NotificationLogEntry, NotificationHistoryQuery } from '../models/notification-log.js';
+import { BaseRepository } from './base.repository.js';
+
+export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
+  constructor(db: Database) {
+    super(db, 'notification_logs');
+  }
+
+  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
+    return {
+      id: record['id'] as string,
+      notificationId: record['notificationId'] as string,
+      recipient: record['recipient'] as string,
+      channel: record['channel'] as NotificationLogEntry['channel'],
+      type: record['type'] as NotificationLogEntry['type'],
+      priority: record['priority'] as NotificationLogEntry['priority'],
+      subject: record['subject'] as string,
+      status: record['status'] as NotificationLogEntry['status'],
+      error: record['error'] as string | undefined,
+      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) : undefined,
+      timestamp: new Date(record['timestamp'] as string),
+    };
+  }
+
+  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
+    return {
+      id: entity.id,
+      notificationId: entity.notificationId,
+      recipient: entity.recipient,
+      channel: entity.channel,
+      type: entity.type,
+      priority: entity.priority,
+      subject: entity.subject,
+      status: entity.status,
+      error: entity.error,
+      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
+      timestamp: entity.timestamp.toISOString(),
+    };
+  }
+
+  /**
+   * Query log entries matching the given filters.
+   */
+  query(filters: NotificationHistoryQuery): NotificationLogEntry[] {
+    return this.findAll((entry) => {
+      if (filters.recipient && entry.recipient !== filters.recipient) return false;
+      if (filters.type && entry.type !== filters.type) return false;
+      if (filters.channel && entry.channel !== filters.channel) return false;
+      if (filters.status && entry.status !== filters.status) return false;
+      if (filters.from && entry.timestamp < filters.from) return false;
+      if (filters.to && entry.timestamp > filters.to) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Find all log entries for a given recipient.
+   */
+  findByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.findAll((entry) => entry.recipient === recipient);
+  }
+
+  /**
+   * Find all log entries for a given notification type.
+   */
+  findByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
+    return this.findAll((entry) => entry.type === type);
+  }
+}

