+/**
+ * Notification history service — logs and queries sent notifications.
+ *
+ * Integrates with NotificationService to record every notification attempt
+ * (sent, failed, or suppressed). Provides query methods for retrieving
+ * history by recipient, type, channel, status, and date range.
+ */
+
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type {
+  NotificationLogEntry,
+  NotificationHistoryQuery,
+  DeliveryStatus,
+} from '../models/notification-log.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import type { PaginationResult } from '../utils/pagination.js';
+import { paginate } from '../utils/pagination.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `log-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+/** Reset the log ID counter. Useful for testing. */
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Record a notification attempt in the history log.
+   */
+  record(payload: NotificationPayload, result: NotificationResult): NotificationLogEntry {
+    let status: DeliveryStatus;
+    if (result.success) {
+      status = 'sent';
+    } else if (result.error === 'Suppressed by user preferences') {
+      status = 'suppressed';
+    } else {
+      status = 'failed';
+    }
+
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: result.notificationId,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      priority: payload.priority,
+      subject: payload.subject,
+      status,
+      error: result.error,
+      metadata: payload.metadata,
+      timestamp: new Date(),
+    };
+
+    this.repository.save(entry);
+    this.logger.info(`Logged notification ${result.notificationId} (${status}) for ${payload.recipient}`);
+    return entry;
+  }
+
+  /**
+   * Query notification history with filters.
+   */
+  query(filters: NotificationHistoryQuery): NotificationLogEntry[] {
+    return this.repository.query(filters);
+  }
+
+  /**
+   * Query notification history with pagination.
+   */
+  queryPaginated(
+    filters: NotificationHistoryQuery,
+    page: number = 1,
+    pageSize: number = 20,
+  ): PaginationResult<NotificationLogEntry> {
+    const entries = this.repository.query(filters);
+    return paginate(entries, page, pageSize);
+  }
+
+  /**
+   * Get all history entries for a recipient.
+   */
+  getByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all history entries for a notification type.
+   */
+  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all history entries within a date range.
+   */
+  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
+    return this.repository.query({ from, to });
+  }
+
+  /**
+   * Get total count of log entries.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLogEntry | undefined {
+    return this.repository.findById(id);
+  }
+}

