 *
 * Captures recipient, channel, type, timestamp, and delivery status for
 * auditing, debugging, and history queries.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';

export interface NotificationLogEntry {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  subject: string;
  status: DeliveryStatus;
  error?: string;
  metadata?: Record<string, string>;
  timestamp: Date;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  from?: Date;
  to?: Date;
}

/**
 * Repository for notification log entries.
 *
 * Extends BaseRepository with query methods for filtering by
 * recipient, type, channel, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLogEntry, NotificationHistoryQuery } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLogEntry['channel'],
      type: record['type'] as NotificationLogEntry['type'],
      priority: record['priority'] as NotificationLogEntry['priority'],
      subject: record['subject'] as string,
      status: record['status'] as NotificationLogEntry['status'],
      error: record['error'] as string | undefined,
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) : undefined,
      timestamp: new Date(record['timestamp'] as string),
    };
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
      timestamp: entity.timestamp.toISOString(),
    };
  }

  /**
   * Query log entries matching the given filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.findAll((entry) => {
      if (filters.recipient && entry.recipient !== filters.recipient) return false;
      if (filters.type && entry.type !== filters.type) return false;
      if (filters.channel && entry.channel !== filters.channel) return false;
      if (filters.status && entry.status !== filters.status) return false;
      if (filters.from && entry.timestamp < filters.from) return false;
      if (filters.to && entry.timestamp > filters.to) return false;
      return true;
    });
  }

  /**
   * Find all log entries for a given recipient.
   */
  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  /**
   * Find all log entries for a given notification type.
   */
  findByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Integrates with NotificationService to record every notification attempt
 * (sent, failed, or suppressed). Provides query methods for retrieving
 * history by recipient, type, channel, status, and date range.
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { PaginationResult } from '../utils/pagination.js';
import { paginate } from '../utils/pagination.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter. Useful for testing. */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a notification attempt in the history log.
   */
  record(payload: NotificationPayload, result: NotificationResult): NotificationLogEntry {
    let status: DeliveryStatus;
    if (result.success) {
      status = 'sent';
    } else if (result.error === 'Suppressed by user preferences') {
      status = 'suppressed';
    } else {
      status = 'failed';
    }

    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: result.notificationId,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      subject: payload.subject,
      status,
      error: result.error,
      metadata: payload.metadata,
      timestamp: new Date(),
    };

    this.repository.save(entry);
    this.logger.info(`Logged notification ${result.notificationId} (${status}) for ${payload.recipient}`);
    return entry;
  }

  /**
   * Query notification history with filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.repository.query(filters);
  }

  /**
   * Query notification history with pagination.
   */
  queryPaginated(
    filters: NotificationHistoryQuery,
    page: number = 1,
    pageSize: number = 20,
  ): PaginationResult<NotificationLogEntry> {
    const entries = this.repository.query(filters);
    return paginate(entries, page, pageSize);
  }

  /**
   * Get all history entries for a recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all history entries for a notification type.
   */
  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all history entries within a date range.
   */
  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
    return this.repository.query({ from, to });
  }

  /**
   * Get total count of log entries.
   */
  getCount(): number {
    return this.repository.count();
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLogEntry | undefined {
    return this.repository.findById(id);
  }
}

