import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

function createSuccessAdapter(): NotificationAdapter {
  return {
    channel: 'email',
    async send(payload: NotificationPayload): Promise<NotificationResult> {
      return { success: true, notificationId: '', channel: payload.channel };
    },
  };
}

function createFailingAdapter(): NotificationAdapter {
  return {
    channel: 'email',
    async send(payload: NotificationPayload): Promise<NotificationResult> {
      return { success: false, notificationId: '', channel: payload.channel, error: 'Delivery failed' };
    },
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a successful notification', () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
        metadata: { orderId: 'order-1' },
      };
      const result: NotificationResult = {
        success: true,
        notificationId: 'notif-0001',
        channel: 'email',
      };

      const entry = historyService.record(payload, result);

      expect(entry.id).toBe('log-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order:confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.error).toBeUndefined();
      expect(entry.timestamp).toBeInstanceOf(Date);
    });

    it('should record a failed notification', () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: 'bob@example.com',
        subject: 'Order Update',
        body: 'Status changed.',
        channel: 'email',
        priority: 'normal',
      };
      const result: NotificationResult = {
        success: false,
        notificationId: 'notif-0002',
        channel: 'email',
        error: 'No adapter for channel: email',
      };

      const entry = historyService.record(payload, result);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('No adapter for channel: email');
    });

    it('should record a suppressed notification', () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'carol@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
      };
      const result: NotificationResult = {
        success: false,
        notificationId: 'notif-0003',
        channel: 'email',
        error: 'Suppressed by user preferences',
      };

      const entry = historyService.record(payload, result);

      expect(entry.status).toBe('suppressed');
      expect(entry.error).toBe('Suppressed by user preferences');
    });

    it('should generate sequential log IDs', () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        priority: 'normal',
      };
      const result: NotificationResult = { success: true, notificationId: 'n1', channel: 'email' };

      const entry1 = historyService.record(payload, result);
      const entry2 = historyService.record(payload, { ...result, notificationId: 'n2' });

      expect(entry1.id).toBe('log-0001');
      expect(entry2.id).toBe('log-0002');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      const entries: Array<{ payload: NotificationPayload; result: NotificationResult }> = [
        {
          payload: { type: 'order:confirmation', recipient: 'alice@example.com', subject: 'S1', body: 'B1', channel: 'email', priority: 'normal' },
          result: { success: true, notificationId: 'n1', channel: 'email' },
        },
        {
          payload: { type: 'order:status-update', recipient: 'alice@example.com', subject: 'S2', body: 'B2', channel: 'email', priority: 'normal' },
          result: { success: true, notificationId: 'n2', channel: 'email' },
        },
        {
          payload: { type: 'order:confirmation', recipient: 'bob@example.com', subject: 'S3', body: 'B3', channel: 'webhook', priority: 'high' },
          result: { success: false, notificationId: 'n3', channel: 'webhook', error: 'Delivery failed' },
        },
      ];
      for (const { payload, result } of entries) {
        historyService.record(payload, result);
      }
    });

    it('should query by recipient', () => {
      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by type', () => {
      const results = historyService.getByType('order:confirmation');
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.type === 'order:confirmation')).toBe(true);
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order:confirmation',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.subject).toBe('S1');
    });

    it('should return empty for non-matching query', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });

    it('should query by date range', () => {
      const now = new Date();
      const past = new Date(now.getTime() - 60000);
      const future = new Date(now.getTime() + 60000);

      const results = historyService.getByDateRange(past, future);
      expect(results).toHaveLength(3);

      const noResults = historyService.getByDateRange(
        new Date('2020-01-01'),
        new Date('2020-01-02'),
      );
      expect(noResults).toHaveLength(0);
    });
  });

  describe('queryPaginated', () => {
    beforeEach(() => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
        priority: 'normal',
      };
      for (let i = 0; i < 5; i++) {
        historyService.record(payload, { success: true, notificationId: `n${i}`, channel: 'email' });
      }
    });

    it('should paginate results', () => {
      const page1 = historyService.queryPaginated({}, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);

      const page3 = historyService.queryPaginated({}, 3, 2);
      expect(page3.items).toHaveLength(1);
      expect(page3.hasNext).toBe(false);
      expect(page3.hasPrevious).toBe(true);
    });
  });

  describe('count and getById', () => {
    it('should return total count', () => {
      expect(historyService.getCount()).toBe(0);

      historyService.record(
        { type: 'order:confirmation', recipient: 'a@b.com', subject: 'S', body: 'B', channel: 'email', priority: 'normal' },
        { success: true, notificationId: 'n1', channel: 'email' },
      );

      expect(historyService.getCount()).toBe(1);
    });

    it('should find entry by ID', () => {
      historyService.record(
        { type: 'order:confirmation', recipient: 'a@b.com', subject: 'S', body: 'B', channel: 'email', priority: 'normal' },
        { success: true, notificationId: 'n1', channel: 'email' },
      );

      const entry = historyService.getById('log-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('n1');

      expect(historyService.getById('nonexistent')).toBeUndefined();
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via NotificationService', async () => {
      notificationService.registerAdapter(createSuccessAdapter());

      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
      });

      expect(historyService.getCount()).toBe(1);
      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('sent');
      expect(entries[0]?.notificationId).toBe('notif-0001');
    });

    it('should log failed notifications', async () => {
      notificationService.registerAdapter(createFailingAdapter());

      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
      });

      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('failed');
    });

    it('should log notifications when no adapter is registered', async () => {
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
      });

      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('failed');
      expect(entries[0]?.error).toContain('No adapter');
    });

    it('should log notifications triggered by events', async () => {
      notificationService.registerAdapter(createSuccessAdapter());

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const entries = historyService.query({ type: 'order:confirmation' });
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('sent');
    });
  });
});
